import { useState, type ReactNode } from 'react';
import { CheckCircle2, Circle, ListChecks } from 'lucide-react';
import { Button } from '@components/ui/button';
import { ConfirmModal } from '@components/ConfirmModal';
import { deskCalloutClass } from '@components/deskCalloutStyles';
import { t } from '@core/i18n';
import type { AdminTabId, SetupProgressItem, SetupProgressPayload, StaffProvisionResult } from './adminTypes';
import { ADMIN_TABS } from './adminTypes';
import { AdminSection } from './adminUi';
import { printHandoverSheet } from './printHandoverSheet';

interface SetupChecklistCardProps {
  progress: SetupProgressPayload;
  markingKey: string | null;
  completing: boolean;
  reopening: boolean;
  /** Which clinic (or the global default) this score belongs to. */
  scopeLabel?: string;
  /** True when the scope picker is on "All facilities" — setup is per clinic. */
  globalScope?: boolean;
  onMarkItem: (key: string) => void;
  onUnmarkItem: (key: string) => void;
  onMarkComplete: () => void;
  onReopen: () => void;
  /** "Take me there" navigation for items whose work lives on another tab. */
  onNavigateTab: (tab: AdminTabId) => void;
  /** Creates sign-ins for the missing core roles (reception, doctor). */
  onProvisionStaff: () => void;
  provisioning: boolean;
  /** One-time result with temp passwords — shown until dismissed, never refetchable. */
  provisionResult: StaffProvisionResult | null;
  onDismissProvisionResult: () => void;
}

function isAdminTab(value: string | null | undefined): value is AdminTabId {
  return typeof value === 'string' && ADMIN_TABS.some((tab) => tab.id === value);
}

function tabLabel(tabId: AdminTabId): string {
  return ADMIN_TABS.find((tab) => tab.id === tabId)?.label ?? tabId;
}

export function SetupChecklistCard({
  progress,
  markingKey,
  completing,
  reopening,
  scopeLabel,
  globalScope = false,
  onMarkItem,
  onUnmarkItem,
  onMarkComplete,
  onReopen,
  onNavigateTab,
  onProvisionStaff,
  provisioning,
  provisionResult,
  onDismissProvisionResult,
}: SetupChecklistCardProps) {
  const [provisionConfirmOpen, setProvisionConfirmOpen] = useState(false);
  const threshold = progress.score_threshold ?? 70;
  const remaining = progress.items.filter((item) => !item.completed);

  // Setup is a per-clinic exercise — under "All facilities" the card would be
  // scoring facility 0, which can never truthfully complete (cash profile,
  // fees and visit types are all per clinic).
  if (globalScope) {
    return (
      <AdminSection
        id="nc-admin-setup-checklist"
        title={t('Setup checklist')}
        description={t('Setup is tracked per clinic.')}
        icon={<ListChecks className="h-4 w-4" aria-hidden />}
      >
        <p className="mb-0 text-sm text-[var(--oe-nc-text-muted)]">
          {t('Switch the picker above to your clinic to see and complete its setup checklist.')}
        </p>
      </AdminSection>
    );
  }

  const provisionResultPanel = provisionResult && (
    <div className={deskCalloutClass('warn', 'mb-3 text-sm')} role="alert">
      {provisionResult.created.length ? (
        <>
          <p className="mb-2 font-semibold">
            {t('Write these down now — the temporary passwords are shown only once.')}
          </p>
          <ul className="mb-2 list-none p-0">
            {provisionResult.created.map((row) => (
              <li key={row.role} className="mb-1">
                <strong>{row.role_label}</strong>
                {' — '}
                {t('sign-in')} <code className="font-mono">{row.username}</code>
                {row.temp_password && (
                  <>
                    {' · '}
                    {t('password')} <code className="font-mono">{row.temp_password}</code>
                  </>
                )}
              </li>
            ))}
          </ul>
          <p className="mb-2 text-[var(--oe-nc-text-muted)]">
            {t('Ask each person to sign in and change their password from My profile.')}
          </p>
        </>
      ) : (
        <p className="mb-2">{t('Every role already has a sign-in — nothing was created.')}</p>
      )}
      <div className="flex flex-wrap items-center gap-2">
        {provisionResult.created.length > 0 && (
          <Button
            type="button"
            size="sm"
            onClick={() => printHandoverSheet(provisionResult.created, scopeLabel)}
          >
            {t('Print handover sheet')}
          </Button>
        )}
        <Button type="button" variant="outline" size="sm" onClick={onDismissProvisionResult}>
          {provisionResult.created.length ? t('I have written these down') : t('OK')}
        </Button>
      </div>
    </div>
  );

  const provisionConfirm = (
    <ConfirmModal
      open={provisionConfirmOpen}
      onClose={() => setProvisionConfirmOpen(false)}
      title={t('Create starter sign-ins?')}
      modalId="nc-admin-provision-staff-modal"
      confirmLabel={t('Create sign-ins')}
      onConfirm={() => {
        setProvisionConfirmOpen(false);
        onProvisionStaff();
      }}
    >
      <p className="mb-0">
        {t('This creates a sign-in for each core role that has none yet (reception, doctor, cashier), with a temporary password shown once. You stay the admin.')}
      </p>
    </ConfirmModal>
  );

  if (progress.setup_complete) {
    return (
      <AdminSection
        id="nc-admin-setup-checklist"
        title={t('Setup complete')}
        description={
          remaining.length
            ? t('Marked complete at {pct}% — {count} item(s) still open below.', {
              pct: String(progress.score_percent),
              count: String(remaining.length),
            })
            : t('Every checklist item is finished.')
        }
        icon={<CheckCircle2 className="h-4 w-4" aria-hidden />}
        variant="success"
        action={(
          <Button
            type="button"
            size="sm"
            variant="outline"
            disabled={reopening}
            onClick={onReopen}
          >
            {reopening ? t('Reopening…') : t('Reopen setup')}
          </Button>
        )}
      >
        {scopeLabel && (
          <p className="mb-2 text-xs text-[var(--oe-nc-text-muted)]">
            {t('Scoring: {scope}', { scope: scopeLabel })}
          </p>
        )}
        {provisionResultPanel}
        {remaining.length ? (
          <ul className="m-0 list-none p-0">
            {remaining.map((item) => (
              <SetupChecklistRow
                key={item.key}
                item={item}
                marking={markingKey === item.key}
                onMark={() => onMarkItem(item.key)}
                onUnmark={() => onUnmarkItem(item.key)}
                onNavigateTab={onNavigateTab}
                extraAction={item.key === 'staff_accounts' ? (
                  <Button
                    type="button"
                    variant="outline"
                    size="sm"
                    className="ml-2 shrink-0"
                    disabled={provisioning}
                    aria-busy={provisioning}
                    onClick={() => setProvisionConfirmOpen(true)}
                  >
                    {provisioning ? t('Creating…') : t('Create starter sign-ins')}
                  </Button>
                ) : undefined}
              />
            ))}
          </ul>
        ) : (
          <p className="mb-0 text-sm font-medium text-[var(--color-oe-cta,#047857)]">
            {t('This clinic is ready for day-to-day operations.')}
          </p>
        )}
        {provisionConfirm}
      </AdminSection>
    );
  }

  return (
    <AdminSection
      id="nc-admin-setup-checklist"
      title={t('Setup checklist')}
      description={t('Get this clinic ready to run — {pct}% done', { pct: String(progress.score_percent) })}
      icon={<ListChecks className="h-4 w-4" aria-hidden />}
      variant="accent"
      action={
        progress.can_mark_complete ? (
          <Button
            type="button"
            size="sm"
            variant="cta"
            disabled={completing}
            onClick={onMarkComplete}
          >
            {completing ? t('Saving…') : t('Mark setup complete')}
          </Button>
        ) : undefined
      }
    >
      {scopeLabel && (
        <p className="mb-2 text-xs text-[var(--oe-nc-text-muted)]">
          {t('Scoring: {scope}', { scope: scopeLabel })}
        </p>
      )}
      <div
        className="nc-admin-progress mb-2"
        role="progressbar"
        aria-label={t('Setup progress')}
        aria-valuenow={progress.score_percent}
        aria-valuemin={0}
        aria-valuemax={100}
      >
        <div className="nc-admin-progress__bar" style={{ width: `${progress.score_percent}%` }} />
      </div>

      {!progress.can_mark_complete && (
        <p className="mb-3 text-xs text-[var(--oe-nc-text-muted)]">
          {t('You can mark setup complete once you reach {threshold}% — currently {pct}%.', {
            threshold: String(threshold),
            pct: String(progress.score_percent),
          })}
        </p>
      )}

      {provisionResultPanel}

      <ul className="m-0 list-none p-0">
        {progress.items.map((item) => (
          <SetupChecklistRow
            key={item.key}
            item={item}
            marking={markingKey === item.key}
            onMark={() => onMarkItem(item.key)}
            onUnmark={() => onUnmarkItem(item.key)}
            onNavigateTab={onNavigateTab}
            extraAction={item.key === 'staff_accounts' && !item.completed ? (
              <Button
                type="button"
                variant="outline"
                size="sm"
                className="ml-2 shrink-0"
                disabled={provisioning}
                aria-busy={provisioning}
                onClick={() => setProvisionConfirmOpen(true)}
              >
                {provisioning ? t('Creating…') : t('Create starter sign-ins')}
              </Button>
            ) : undefined}
          />
        ))}
      </ul>
      {provisionConfirm}
    </AdminSection>
  );
}

function SetupChecklistRow({
  item,
  marking,
  onMark,
  onUnmark,
  onNavigateTab,
  extraAction,
}: {
  item: SetupProgressItem;
  marking: boolean;
  onMark: () => void;
  onUnmark: () => void;
  onNavigateTab: (tab: AdminTabId) => void;
  extraAction?: ReactNode;
}) {
  // The card only renders on the System tab, so a "take me there" link to
  // the System tab itself would be noise — the hint already says "below".
  const linkTab = isAdminTab(item.link_tab) && item.link_tab !== 'system' ? item.link_tab : null;

  return (
    <li className="flex items-start border-b border-[var(--oe-nc-border)]/70 py-2 last:border-b-0">
      {item.completed ? (
        <CheckCircle2 className="mr-2 mt-0.5 h-4 w-4 shrink-0 text-[var(--color-oe-cta,#047857)]" aria-hidden />
      ) : (
        <Circle className="mr-2 mt-0.5 h-4 w-4 shrink-0 text-[var(--oe-nc-text-muted)]" aria-hidden />
      )}
      <div className="min-w-0 flex-grow">
        <div className="text-sm font-semibold">
          {/* State is announced, not just drawn (the icons are aria-hidden). */}
          <span className="sr-only">{item.completed ? t('Done:') : t('To do:')} </span>
          {item.label}
          <span className="ml-2 text-xs font-normal text-[var(--oe-nc-text-muted)]">
            +{item.weight}%
          </span>
        </div>
        {!item.completed && item.hint && (
          <div className="text-sm text-[var(--oe-nc-text-muted)]">
            {item.hint}
            {linkTab && (
              <>
                {' '}
                <Button
                  type="button"
                  variant="link"
                  size="sm"
                  className="h-auto p-0 align-baseline"
                  onClick={() => onNavigateTab(linkTab)}
                >
                  {t('Open {tab} →', { tab: tabLabel(linkTab) })}
                </Button>
              </>
            )}
            {!linkTab && item.link_anchor && (
              <>
                {' '}
                <Button
                  type="button"
                  variant="link"
                  size="sm"
                  className="h-auto p-0 align-baseline"
                  onClick={() => {
                    document.getElementById(item.link_anchor!)?.scrollIntoView({ behavior: 'smooth', block: 'start' });
                  }}
                >
                  {t('See runbooks below →')}
                </Button>
              </>
            )}
          </div>
        )}
      </div>
      {extraAction}
      {item.manual && !item.completed && (
        <Button
          type="button"
          variant="outline"
          size="sm"
          className="ml-2 shrink-0"
          disabled={marking}
          aria-busy={marking}
          aria-label={t('Mark "{item}" done', { item: item.label })}
          onClick={onMark}
        >
          {marking ? t('Saving…') : t('Mark done')}
        </Button>
      )}
      {item.manual && item.completed && item.ticked && (
        <Button
          type="button"
          variant="link"
          size="sm"
          className="ml-2 h-auto shrink-0 p-0"
          disabled={marking}
          aria-busy={marking}
          aria-label={t('Untick "{item}"', { item: item.label })}
          onClick={onUnmark}
        >
          {marking ? t('Saving…') : t('Undo')}
        </Button>
      )}
    </li>
  );
}
